n = int(input())
promocodes = []
for i in range(n):
    promocodes.append(input())

def check(promocode, promocodes):
    count = 0
    for i in range(len(promocode)):
        if promocode[i] != promocodes[i]:
            count += 1
    return count

k = len(promocodes[0])
for promocode in promocodes:
    for i in range(len(promocode)):
        new_promocode = promocode[:i] + str((int(promocode[i]) + 1) % 10) + promocode[i + 1:]
        if check(new_promocode, promocode) < k:
            k = check(new_promocode, promocode)
print(k)
